#include <stdio.h>
#include <string.h>

#define MAXN 1005

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, seed;
        char use_numbers[5];
        char use_special[5];
        scanf("%d", &N);
        scanf("%4s", use_numbers);
        scanf("%d", &seed); // ignored
        scanf("%4s", use_special);
        char password[MAXN];
        int idx = 0; // index in alphabet, 0 -> 'a'
        int pos = 0;
        for (int i = 0; i < N - 2; ++i) {
            password[pos++] = 'a' + (idx % 26);
            idx++;
        }
        // (N-1)th character
        if (strcmp(use_numbers, "Yes") == 0) {
            password[pos++] = '1';
        } else {
            password[pos++] = 'a' + (idx % 26);
            idx++;
        }
        // Nth character
        if (strcmp(use_special, "Yes") == 0) {
            password[pos++] = '!';
        } else {
            password[pos++] = 'a' + (idx % 26);
            idx++;
        }
        password[pos] = '\0';
        printf("%s\n", password);
    }
    return 0;
}

