        for(int i=0;i<N-2;i++) {
            password.push_back('a' + (idx%26));
            ++idx;
        }
        if(use_numbers=="Yes") password.push_back('1');
        else { password.push_back('a' + (idx%26)); ++idx; }
        if(use_special=="Yes") password.push_back('!');
        else { password.push_back('a' + (idx%26)); ++idx; }
        cout<<password<<"\n";
    }
    return 0;
