public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(br.readLine().trim());
            String useNumbers = br.readLine().trim();
            int seed = Integer.parseInt(br.readLine().trim()); // ignored
            String useSpecial = br.readLine().trim();
            StringBuilder pwd = new StringBuilder();
            int idx = 0;
            for (int i = 0; i < N - 2; i++) {
                pwd.append((char)('a' + (idx % 26)));
                idx++;
            }
            if (useNumbers.equals("Yes")) pwd.append('1');
            else { pwd.append((char)('a' + (idx % 26))); idx++; }
            if (useSpecial.equals("Yes")) pwd.append('!');
            else { pwd.append((char)('a' + (idx % 26))); idx++; }
            out.append(pwd).append('\n');
        }
        System.out.print(out.toString());
    }
}

